        body {
            background: radial-gradient circle at center, #0a0a0a 0%, #0a0a0a 100%;
            min-height: 100vh;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            padding: 20px;
        }
        .page-wrapper {
            max-width: 900px;
            width: 100%;
            background: rgba(0, 0, 0, 0.8);
            border: 1px solid #0f0;
            box-shadow: 0 0 20px #0f0, 0 0 40px #0f0, inset 0 0 20px #0f0;
            border-radius: 12px;
            padding: 2rem 1.5rem;
            backdrop-filter: blur(2px);
        }
        header {
            text-align: center;
            margin-bottom: 2rem;
        }
        h1 {
            font-size: 2.5rem;
            text-transform: uppercase;
            letter-spacing: 4px;
            color: #0f0;
            text-shadow: 0 0 10px #0f0, 0 0 20px #0f0, 0 0 40px #0f0;
            margin: 0 0 0.5rem;
        }
        .sub-title {
            color: #b0f0b0;
            font-size: 1.2rem;
            border-bottom: 1px dashed #0f0;
            padding-bottom: 0.5rem;
        }
        .hero {
            background: #0a0a0a;
            border: 1px solid #0f0;
            padding: 1.5rem;
            border-radius: 8px;
            margin-bottom: 2rem;
            box-shadow: 0 0 10px #0f0 inset;
        }
        .hero p {
            font-size: 1.1rem;
            line-height: 1.6;
        }
        .hero .tag {
            color: #0f0;
            font-weight: bold;
        }
        .grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(150px, 1fr);
            gap: 1rem;
            margin: 2rem 0;
        }
        .card {
            background: #000;
            border: 1px solid #0f0;
            padding: 1rem;
            border-radius: 6px;
            text-align: center;
            transition: 0.2s;
        }
        .card:hover {
            box-shadow: 0 0 10px #0f0, 0 0 20px #0f0;
        }
        .card h3 {
            color: #0f0;
            margin: 0 0 0.5rem;
        }
        .card p {
            font-size: 0.9rem;
            color: #ccc;
        }
        .form-area {
            background: #0a0a0a;
            border: 1px solid #0f0;
            padding: 1.5rem;
            border-radius: 8px;
            margin: 2rem 0;
        }
        .form-area h2 {
            color: #0f0;
            margin-top: 0;
        }
        form {
            display: flex;
            flex-direction: column;
            gap: 1.5rem;
        }
        .form-group {
            display: flex;
            flex-direction: column;
            gap: 0.5rem;
        }
        label {
            color: #0f0;
            font-weight: bold;
        }
        input, textarea {
            background: #000;
            border: 1px solid #0f0;
            padding: 0.8rem;
            border-radius: 4px;
            color: #0f0;
            font-size: 1rem;
        }
        input:focus, textarea:focus {
            outline: none;
            box-shadow: 0 0 5px #0f0;
        }
        button {
            background: #0f0;
            color: #000;
            border: none;
            padding: 1rem 2rem;
