</head>
<body>
    <div class="page-wrapper">
        <header>
            <h1>AI Code Shop</h1>
            <div class="sub-title">Negozio di Programmazione AI - CyberPunk</div>
        </header>
        <section class="hero">
            <p><span class="tag">� Neut Net</span> — Acquista modelli di sintetizzazione neurale, potenze di calcolo quantistico, esprazioni di coscienza artificiale. Tutti i nostri codici sono certificati da protocolli di sicurezza cbernetica.</p>
        </section>
        <div class="grid">
            <div class="card">
                <h3>AI Brain v1</h3>
                <p>Modello di rete neurale per ottimizzare processi di deep learning.</p>
            </div>
            <div class="card">
                <h3>SynC 2</h3>
                <p>Processo di sintetizzazione dati per AI quantistica.</p>
            </div>
            <div class="card">
                <h3>NeuroX 3</h3>
                <p>Esprazioni di coscienza per AI generativa.</p>
            </div>
            <div class="card">
                <h3>CodeMatrix</h3>
                <p>Libreria di codici per AI programmazione.</p>
            </div>
            <div class="card">
                <h3>QuantNet</h3>
                <p>Rete di calcolo quantistico per AI.</p>
            </div>
            <div class="card">
                <h3>CyberMind</h3>
                <p>Modello di coscienza artificiale avanzato.</p>
            </div>
        </div>
        <div class="form-area">
        <h2>Contattaci — Richiesta Codice</h2>
        <form>
        <div class="form-group">
            <label for="nome">Nome</label>
            <input type="text" id="nome" placeholder="Inserisci il tuo nome">
        </div>
        <div class="form-group">
            <label for="email">Email</label>
            <input type="email" id="email" placeholder="Inserisci la tua email">
        </div>
        <div class="form-group">
            <label for="message">Richiesta</label>
            <textarea id="message" rows="4" placeholder="Descrivi la tua richiesta..."></textarea>
        </div>
        <button type="button" id="inviaBtn">Invia Richiesta</button>
        <div class="error-m" id="error-m" style="hidden"></div>
        </form>
    </div>
    <footer>
        <p>AI Code Shop - 202- CyberPunk</p>
    </footer>
    </div>
    <!-- popup-over -->
    <div class="popup-over" id="popupOver">
        <div class="popup-box">
            <h2>Richiesta Inviata</h2>
            <p>Il tuo messaggio è stato inviato con successo nella rete neurale.</p>
            <button class="glic-btn" id="closePopup">OK</button>
        </div>
    </div>
    <script>
        document.addEventListener, DOM, ready, function (form) non form.
        const btn = document.getElementById('inviaBtn');
        const popupOver = document.getElementById('popupOver');
        const closeBtn = document.getElementById('closePopup');
        const errorDiv = document.getElementById('error-m');
        const nome = document.getElementById('nome');
        const email = document.getElementById('email');
        const message = document.getElementById('message');

        btn.addEventListener('click', function (e) {
            e.preventDefault();
            let error = '';
            if nome.value.trim() === '' || email.value.trim() === '' || message.value.trim() === '' || error = 'Compia tutti campi';
            if error) {
                errorDiv.textContent = error;
                errorDiv.style.visibility = 'block';
                return;
            }
            if email.value.indexOf('@') === -1 || email.value.indexOf('.') === -1) {
                error = 'Inserisci una email valida';
                errorDiv.textContent = error;
                errorDiv.style.visibility = 'block';
                return;
            }
            errorDiv.style.visibility = 'hidden';
            popupOver.classList.add('show');
            // form.reset();
        }

        closeBtn.addEventListener('click', function () {
            popupOver.classList.remove('show');
        });

        window.addEventListener('click', function (e) {
            if e.target === popupOver) {
                popupOver.classList.remove('show');
            }
        });
    </script>
